import React, { useState } from "react";
import { ethers } from "ethers";
import Web3Modal from "web3modal";
import { CONTRACT_ADDRESS, CONTRACT_ABI } from "../../constants";

export default function ServiceDashboard() {
  const [address, setAddress] = useState("");
  const [requiredLevel, setRequiredLevel] = useState(1);
  const [msg, setMsg] = useState("");

  const checkAccess = async () => {
    try {
      const web3Modal = new Web3Modal();
      const conn = await web3Modal.connect();
      const provider = new ethers.providers.Web3Provider(conn);
      const signer = provider.getSigner();
      const addr = await signer.getAddress();
      setAddress(addr);

      const contract = new ethers.Contract(CONTRACT_ADDRESS, CONTRACT_ABI, provider);
      const ok = await contract.isVerifiedAtLevel(addr, Number(requiredLevel));
      if (ok) {
        setMsg("✅ Service access granted based on reusable KYC.");
      } else {
        setMsg(
          "❌ Service access denied. You must complete KYC at required level."
        );
      }
    } catch (err) {
      console.error(err);
      setMsg("❌ " + (err.reason || err.message));
    }
  };

  return (
    <div className="card">
      <h2>Service Provider Demo</h2>
      <p className="muted">
        This simulates a DeFi app, CEX, or lending protocol checking your KYC
        once before giving access.
      </p>
      {address && (
        <p>
          Caller: <code>{address}</code>
        </p>
      )}
      <label>Required KYC level for this service</label>
      <select
        value={requiredLevel}
        onChange={e => setRequiredLevel(e.target.value)}
      >
        <option value={1}>1 - Basic</option>
        <option value={2}>2 - Enhanced</option>
      </select>
      <button onClick={checkAccess}>Check Access</button>
      {msg && <p>{msg}</p>}
    </div>
  );
}
